            raise ValueError("unexpected token")
        return node

    def parse_expression(self) -> ASTNode:
        node = self.parse_term()
        while True:
            token = self.peek()
            if token and token.type == "OPERATOR" and token.value in "+-":
                op = token.value
                self.consume()
                right = self.parse_term()
                node = ASTNode(NodeType.BINOP, op=op, left=node, right=right)
            else:
                break
        return node

    def parse_term(self) -> ASTNode:
        node = self.parse_factor()
        while True:
            token = self.peek()
            if token and token.type == "OPERATOR" and token.value in "*/":
                op = token.value
                self.consume()
                right = self.parse_factor()
                node = ASTNode(NodeType.BINOP, op=op, left=node, right=right)
            else:
                break
        return node

    def parse_factor(self) -> ASTNode:
        token = self.peek()
        if token is None:
            raise ValueError("unexpected end of input")
        if token.type == "NUMBER":
            self.consume()
            return ASTNode(NodeType.NUMBER, value=token.value)
        elif token.type == "OPERATOR" and token.value == "(":
            self.consume()
            node = self.parse_expression()
            next_token = self.consume()
            if (
                next_token is None
                or next_token.type != "OPERATOR"
                or next_token.value != ")"
            ):
                raise ValueError("unmatched parenthesis")
            return node
        elif token.type == "OPERATOR" and token.value in "+-":
            op = token.value
            self.consume()
            operand = self.parse_factor()
            return ASTNode(NodeType.UNARY, op=op, operand=operand)
        else:
            raise ValueError(f"unexpected token: {token}")


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("empty input")
    tokenizer = Tokenizer(expression.strip())
    tokens = tokenizer.tokenize()
    parser = Parser(tokens)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    return node.evaluate()


__all__ = ["ASTNode", "parse", "evaluate", "NodeType"]
